import React from "react";
import "./Section.css";

function BloodBank() {
  return (
    <div className="section-card">
      <div className="icon">🩸</div>
      <h3>Blood Bank Information</h3>
      <p>Get real-time information on blood availability and connect with blood banks.</p>
    </div>
  );
}

export default BloodBank;
